---
/**
 * Map.astro -- astro-shad map container. Converted from mapcn's map.tsx
 * (React + MapLibre GL): the React layer was lifecycle glue around MapLibre's
 * own imperative API, so the port keeps the MapLibre calls and replaces the
 * wiring -- context/portals/controlled-viewport deleted, one component
 * <script> initialises every map on the page.
 *
 * Composition contract (how children attach):
 *   - The map instance is stored on the root element as `__astroShadMap` and
 *     announced with a `map:ready` CustomEvent (detail.map). Child components
 *     (MapMarker, MapControls, future layer items) find their map via
 *     `closest('[data-astro-shad-map]')` and either read the property or wait
 *     for the event -- both orders are safe, script bundling order is not
 *     guaranteed.
 *   - `map:load` fires once map + initial style are loaded; `map:style-load`
 *     fires after EVERY style swap (theme change reloads the style with
 *     diff:false, wiping sources/layers) -- layer components must re-add
 *     themselves on it. `map:moveend` carries the viewport
 *     ({ center, zoom, bearing, pitch }).
 *
 * Theming: the basemap follows the TOKEN theme, not the OS -- resolved as
 * prop > closest `[data-theme]` ancestor (works inside scoped previews like
 * /dev) > documentElement class, falling back to dark (the token contract's
 * default; light opts in via data-theme, so an absent attribute means dark).
 * Watched with one subtree MutationObserver unless the `theme` prop pins it.
 * Basemaps default to Carto positron (light) / dark-matter (dark); `styles`
 * overrides them, `blank` swaps in a transparent tile-less style for
 * data-viz layers.
 *
 * The consumer owns the container height -- `h-full w-full` against a parent
 * with no height renders a 0px map (the #1 "my map is blank" cause).
 *
 *   <div class="h-96">
 *     <Map center={[18.4188, -33.9066]} zoom={14}>
 *       <MapMarker longitude={18.4188} latitude={-33.9066}>...</MapMarker>
 *       <MapControls showLocate />
 *     </Map>
 *   </div>
 */
import 'maplibre-gl/dist/maplibre-gl.css';
import { cn } from '../../lib/utils';

type MapStyleOption = string | Record<string, unknown>;

interface Props {
  /** Pin the basemap theme; omit to auto-detect and live-track the page theme. */
  theme?: 'light' | 'dark';
  /** Custom style URL or style-spec object per theme; overrides the Carto defaults. */
  styles?: { light?: MapStyleOption; dark?: MapStyleOption };
  /** Transparent tile-less basemap -- a blank canvas for data-viz layers. Ignored when `styles` is passed. */
  blank?: boolean;
  /** Map projection; `globe` for the 3D globe. Applied after each style load. */
  projection?: 'mercator' | 'globe' | 'vertical-perspective';
  /** Initial center as [longitude, latitude]. */
  center?: [number, number];
  zoom?: number;
  bearing?: number;
  pitch?: number;
  /** Keep the loading overlay up even after the map loads. */
  loading?: boolean;
  /** Extra JSON-serialisable MapLibre MapOptions (minZoom, maxZoom, cooperativeGestures, ...). */
  options?: Record<string, unknown>;
  class?: string;
  [key: string]: unknown;
}

const {
  theme,
  styles,
  blank = false,
  projection,
  center,
  zoom,
  bearing,
  pitch,
  loading = false,
  options,
  class: className,
  ...rest
} = Astro.props;

const config = JSON.stringify({
  theme,
  styles,
  blank,
  projection,
  center,
  zoom,
  bearing,
  pitch,
  options,
});
---

<div
  class={cn('relative h-full w-full overflow-hidden', className)}
  data-astro-shad-map
  data-map-config={config}
  data-loading={loading ? '' : undefined}
  {...rest}
>
  <div
    data-map-loader
    class="pointer-events-none absolute inset-0 z-10 flex items-center justify-center bg-background/50 backdrop-blur-xs"
  >
    <div class="flex gap-1">
      <span class="size-1.5 animate-pulse rounded-full bg-muted-foreground/60"></span>
      <span class="size-1.5 animate-pulse rounded-full bg-muted-foreground/60 [animation-delay:150ms]"></span>
      <span class="size-1.5 animate-pulse rounded-full bg-muted-foreground/60 [animation-delay:300ms]"></span>
    </div>
  </div>
  <slot />
</div>

<style is:global>
  /* Neutralise MapLibre's built-in white popup chrome -- popup content is a
     token-styled card supplied by MapMarker/MapPopup, so the wrapper must be
     invisible. The pointer tip is hidden because popups offset 16px from the
     anchor; a white tip against bg-popover would mismatch in dark theme. */
  [data-astro-shad-map] .maplibregl-popup-content {
    background: transparent;
    padding: 0;
    box-shadow: none;
    border-radius: 0;
  }
  [data-astro-shad-map] .maplibregl-popup-tip {
    display: none;
  }
</style>

<script>
  import MapLibreGL from 'maplibre-gl';

  type Theme = 'light' | 'dark';
  type MapConfig = {
    theme?: Theme;
    styles?: { light?: string | object; dark?: string | object };
    blank?: boolean;
    projection?: string;
    center?: [number, number];
    zoom?: number;
    bearing?: number;
    pitch?: number;
    options?: Record<string, unknown>;
  };

  const DEFAULT_STYLES: Record<Theme, string> = {
    dark: 'https://basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
    light: 'https://basemaps.cartocdn.com/gl/positron-gl-style/style.json',
  };

  // Tile-less transparent style: the themed container shows through; layer
  // components draw on top (choropleths, arcs). Used alone it renders nothing.
  const BLANK_STYLE = {
    version: 8,
    sources: {},
    layers: [
      {
        id: 'background',
        type: 'background',
        paint: { 'background-color': 'rgba(0, 0, 0, 0)' },
      },
    ],
  };

  function resolveTheme(root: HTMLElement): Theme {
    // Nearest scoped theme wins (e.g. a preview wrapper carrying data-theme),
    // then the documentElement class convention. NO system-preference
    // fallback: tokens render dark by default and light opts in via
    // data-theme, so an absent attribute MEANS dark -- following the OS here
    // would put a light basemap under dark token chrome.
    const scoped = root.closest<HTMLElement>('[data-theme]')?.dataset.theme;
    if (scoped === 'dark' || scoped === 'light') return scoped;
    const el = document.documentElement;
    if (el.classList.contains('dark')) return 'dark';
    if (el.classList.contains('light')) return 'light';
    return 'dark';
  }

  function getViewport(map: MapLibreGL.Map) {
    const c = map.getCenter();
    return {
      center: [c.lng, c.lat] as [number, number],
      zoom: map.getZoom(),
      bearing: map.getBearing(),
      pitch: map.getPitch(),
    };
  }

  function initMap(root: HTMLElement) {
    const config: MapConfig = JSON.parse(root.dataset.mapConfig || '{}');

    const styleFor = (t: Theme) => {
      const custom = config.styles?.[t];
      if (custom) return custom;
      if (config.blank) return BLANK_STYLE;
      return DEFAULT_STYLES[t];
    };

    let theme: Theme = config.theme ?? resolveTheme(root);
    // Stamped for layer children (MapGeoJSON's monochrome defaults are
    // theme-aware): read mapRoot.dataset.mapTheme at (re-)add time. Not
    // `data-theme` -- that would feed back into resolveTheme's closest().
    root.dataset.mapTheme = theme;

    const map = new MapLibreGL.Map({
      container: root,
      style: styleFor(theme) as string,
      renderWorldCopies: false,
      attributionControl: { compact: true },
      ...(config.center ? { center: config.center } : {}),
      ...(config.zoom !== undefined ? { zoom: config.zoom } : {}),
      ...(config.bearing !== undefined ? { bearing: config.bearing } : {}),
      ...(config.pitch !== undefined ? { pitch: config.pitch } : {}),
      ...config.options,
    });

    (root as HTMLElement & { __astroShadMap?: MapLibreGL.Map }).__astroShadMap = map;
    const emit = (name: string, detail: Record<string, unknown> = {}) =>
      root.dispatchEvent(new CustomEvent(name, { detail: { map, ...detail } }));

    emit('map:ready');

    map.on('load', () => {
      if (!root.hasAttribute('data-loading')) {
        root.querySelector('[data-map-loader]')?.setAttribute('hidden', '');
      }
      emit('map:load');
    });

    // Fires on the initial style AND after every theme swap. Projection lives
    // in the style, so it must be re-applied here; layer components (routes,
    // geojson, arcs) re-add their sources/layers on this event.
    map.on('style.load', () => {
      if (config.projection) {
        map.setProjection({ type: config.projection } as never);
      }
      emit('map:style-load');
    });

    map.on('moveend', () => emit('map:moveend', { viewport: getViewport(map) }));

    if (!config.theme) {
      const applyTheme = (next: Theme) => {
        if (next === theme) return;
        theme = next;
        root.dataset.mapTheme = theme;
        // Full reload (no diff) so style.load fires deterministically -- a
        // successful diff would never fire it and children would never re-add.
        map.setStyle(styleFor(theme) as string, { diff: false });
      };

      // Subtree observer because the scoped [data-theme] attribute may not
      // exist at init (dark = attribute REMOVED under the token contract) --
      // closest() at setup time would miss the element that later gains it.
      const observer = new MutationObserver(() => applyTheme(resolveTheme(root)));
      observer.observe(document.documentElement, {
        attributes: true,
        subtree: true,
        attributeFilter: ['class', 'data-theme'],
      });
    }
  }

  document.querySelectorAll<HTMLElement>('[data-astro-shad-map]').forEach(initMap);
</script>

---
/**
 * MapMarker.astro -- astro-shad map marker. Converted from mapcn's map.tsx:
 * FIVE React components (MapMarker + MarkerContent + MarkerPopup +
 * MarkerTooltip + MarkerLabel) collapsed into one file with slots. React
 * needed createPortal to inject JSX into MapLibre's DOM; Astro slot content is
 * already real DOM, so the content div is handed straight to
 * `new Marker({ element })` and popup/tooltip markup ships in inert
 * <template> elements the script hands to `Popup.setDOMContent()`.
 *
 * Slots:
 *   - default   -- marker content (falls back to an accent-colored dot)
 *   - popup     -- toggles on marker click / Enter / Space (token card chrome,
 *                  optional close button; closes on map click elsewhere)
 *   - tooltip   -- shows on marker hover (inverse chip chrome)
 *   - label     -- persistent text pinned above/below the marker
 *
 * Must be a child of <Map>. Callback props became CustomEvents dispatched on
 * the map root element (listen on the <Map> wrapper): `map:marker-click`,
 * `map:marker-mouseenter`, `map:marker-mouseleave`, and for draggable markers
 * `map:marker-dragstart` / `map:marker-drag` / `map:marker-dragend` (detail:
 * { id, marker, lngLat }). Pass `id` to tell markers apart in handlers.
 *
 *   <MapMarker longitude={18.42} latitude={-33.91} closeButton>
 *     <span slot="label">Acme Coffee</span>
 *     <div slot="popup">
 *       <p class="text-sm font-semibold">Acme Coffee</p>
 *       <p class="text-xs text-muted-foreground">123 Long Street</p>
 *     </div>
 *   </MapMarker>
 */
import { cn } from '../../lib/utils';

interface Props {
  longitude: number;
  latitude: number;
  /** Identifies this marker in the CustomEvent payloads. */
  id?: string;
  draggable?: boolean;
  /** MapLibre marker anchor (default: "center"). */
  anchor?:
    | 'center'
    | 'top'
    | 'bottom'
    | 'left'
    | 'right'
    | 'top-left'
    | 'top-right'
    | 'bottom-left'
    | 'bottom-right';
  /** Pixel offset [x, y] applied to the marker element. */
  offset?: [number, number];
  /** Rotation in degrees. */
  rotation?: number;
  rotationAlignment?: 'map' | 'viewport' | 'auto';
  pitchAlignment?: 'map' | 'viewport' | 'auto';
  /** Show a close button in the popup (default: false). */
  closeButton?: boolean;
  /** Where the label slot renders relative to the marker (default: "top"). */
  labelPosition?: 'top' | 'bottom';
  /** Extra classes for the marker content wrapper. */
  class?: string;
}

const {
  longitude,
  latitude,
  id,
  draggable = false,
  anchor,
  offset,
  rotation,
  rotationAlignment,
  pitchAlignment,
  closeButton = false,
  labelPosition = 'top',
  class: className,
} = Astro.props;

const hasPopup = Astro.slots.has('popup');
const hasTooltip = Astro.slots.has('tooltip');
const hasLabel = Astro.slots.has('label');

const config = JSON.stringify({
  longitude,
  latitude,
  id,
  draggable,
  anchor,
  offset,
  rotation,
  rotationAlignment,
  pitchAlignment,
});
---

<div data-astro-shad-map-marker data-marker-config={config} hidden>
  <div data-marker-content class={cn('relative cursor-pointer', className)}>
    {
      hasLabel && (
        <div
          class={cn(
            'absolute left-1/2 -translate-x-1/2 text-[10px] font-medium whitespace-nowrap text-foreground',
            labelPosition === 'bottom' ? 'top-full mt-1' : 'bottom-full mb-1',
          )}
        >
          <slot name="label" />
        </div>
      )
    }
    <slot>
      <!-- default pin: bg-accent (the chromatic highlight token -- primary is
           near-monochrome in the neutral theme and vanishes against tiles);
           border-white is literal on purpose, the ring must read against map
           tiles in both themes, not against a token surface -->
      <div class="h-4 w-4 rounded-full border-2 border-white bg-accent shadow-lg"></div>
    </slot>
  </div>

  {
    hasPopup && (
      <template data-marker-popup>
        <div class="relative max-w-62 rounded-md border bg-popover p-3 text-popover-foreground shadow-md">
          {closeButton && (
            <button
              type="button"
              data-popup-close
              aria-label="Close popup"
              class="absolute top-1 right-1 z-10 inline-flex size-5 cursor-pointer items-center justify-center rounded-sm text-foreground transition-colors hover:bg-muted focus:outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-ring"
            >
              <svg
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                stroke-width="2"
                stroke-linecap="round"
                stroke-linejoin="round"
                class="size-3.5"
              >
                <path d="M18 6 6 18" />
                <path d="m6 6 12 12" />
              </svg>
            </button>
          )}
          <slot name="popup" />
        </div>
      </template>
    )
  }

  {
    hasTooltip && (
      <template data-marker-tooltip>
        <div class="pointer-events-none rounded-md bg-foreground px-2 py-1 text-xs text-balance text-background shadow-md">
          <slot name="tooltip" />
        </div>
      </template>
    )
  }
</div>

<script>
  import MapLibreGL from 'maplibre-gl';

  type MarkerConfig = {
    longitude: number;
    latitude: number;
    id?: string;
    draggable?: boolean;
    anchor?: string;
    offset?: [number, number];
    rotation?: number;
    rotationAlignment?: string;
    pitchAlignment?: string;
  };

  // Map may init before or after us -- script bundling order is not guaranteed.
  function whenMapReady(
    el: HTMLElement,
    cb: (map: MapLibreGL.Map, mapRoot: HTMLElement) => void,
  ) {
    const mapRoot = el.closest<HTMLElement>('[data-astro-shad-map]');
    if (!mapRoot) return;
    const existing = (mapRoot as HTMLElement & { __astroShadMap?: MapLibreGL.Map }).__astroShadMap;
    if (existing) cb(existing, mapRoot);
    else
      mapRoot.addEventListener(
        'map:ready',
        (e) => cb((e as CustomEvent).detail.map, mapRoot),
        { once: true },
      );
  }

  function initMarker(el: HTMLElement) {
    whenMapReady(el, (map, mapRoot) => {
      const cfg: MarkerConfig = JSON.parse(el.dataset.markerConfig || '{}');
      const content = el.querySelector<HTMLElement>('[data-marker-content]');
      if (!content) return;

      const marker = new MapLibreGL.Marker({
        element: content,
        draggable: !!cfg.draggable,
        ...(cfg.anchor ? { anchor: cfg.anchor as never } : {}),
        ...(cfg.offset ? { offset: cfg.offset } : {}),
        ...(cfg.rotation !== undefined ? { rotation: cfg.rotation } : {}),
        ...(cfg.rotationAlignment
          ? { rotationAlignment: cfg.rotationAlignment as never }
          : {}),
        ...(cfg.pitchAlignment ? { pitchAlignment: cfg.pitchAlignment as never } : {}),
      })
        .setLngLat([cfg.longitude, cfg.latitude])
        .addTo(map);

      const emit = (name: string, detail: Record<string, unknown> = {}) =>
        mapRoot.dispatchEvent(
          new CustomEvent(name, { detail: { id: cfg.id, marker, ...detail } }),
        );

      content.addEventListener('click', (e) => emit('map:marker-click', { originalEvent: e }));
      content.addEventListener('mouseenter', (e) =>
        emit('map:marker-mouseenter', { originalEvent: e }),
      );
      content.addEventListener('mouseleave', (e) =>
        emit('map:marker-mouseleave', { originalEvent: e }),
      );

      if (cfg.draggable) {
        const dragDetail = () => {
          const { lng, lat } = marker.getLngLat();
          return { lngLat: { lng, lat } };
        };
        marker.on('dragstart', () => emit('map:marker-dragstart', dragDetail()));
        marker.on('drag', () => emit('map:marker-drag', dragDetail()));
        marker.on('dragend', () => emit('map:marker-dragend', dragDetail()));
      }

      const popupTpl = el.querySelector<HTMLTemplateElement>('template[data-marker-popup]');
      const popupEl = popupTpl?.content.firstElementChild as HTMLElement | undefined;
      if (popupEl) {
        const popup = new MapLibreGL.Popup({ offset: 16, closeButton: false })
          .setMaxWidth('none')
          .setDOMContent(popupEl);
        // Toggle ourselves instead of marker.setPopup(): deterministic, and
        // stopPropagation is load-bearing -- without it the click bubbles to
        // the map and the popup's own closeOnClick removes it immediately
        // (the trap maplibre's marker source warns about).
        const togglePopup = () => {
          if (popup.isOpen()) popup.remove();
          else popup.setLngLat(marker.getLngLat()).addTo(map);
        };
        content.addEventListener('click', (e) => {
          e.stopPropagation();
          togglePopup();
        });
        content.tabIndex = 0;
        content.addEventListener('keydown', (e) => {
          if (e.code === 'Space' || e.code === 'Enter') {
            e.preventDefault();
            togglePopup();
          }
        });
        popupEl
          .querySelector('[data-popup-close]')
          ?.addEventListener('click', () => popup.remove());
      }

      const tooltipTpl = el.querySelector<HTMLTemplateElement>('template[data-marker-tooltip]');
      const tooltipEl = tooltipTpl?.content.firstElementChild as HTMLElement | undefined;
      if (tooltipEl) {
        const tooltip = new MapLibreGL.Popup({
          offset: 16,
          closeButton: false,
          closeOnClick: true,
        })
          .setMaxWidth('none')
          .setDOMContent(tooltipEl);
        content.addEventListener('mouseenter', () =>
          tooltip.setLngLat(marker.getLngLat()).addTo(map),
        );
        content.addEventListener('mouseleave', () => tooltip.remove());
      }
    });
  }

  document.querySelectorAll<HTMLElement>('[data-astro-shad-map-marker]').forEach(initMarker);
</script>

---
/**
 * MapControls.astro -- astro-shad map controls. Converted from mapcn's
 * map.tsx MapControls/ControlGroup/ControlButton/CompassButton: zoom in/out,
 * compass (live bearing+pitch needle, click resets north), locate (geolocation
 * + flyTo, 10s timeout so a dismissed permission prompt doesn't wedge the
 * button), and fullscreen toggle on the map container. lucide-react icons
 * inlined as SVGs per the icon rule; hover surfaces use `bg-muted` per the
 * accent-token decision (mapcn used hover:bg-accent + a dark: variant --
 * registry markup carries no dark: variants, tokens flip instead).
 *
 * Must be a child of <Map>. A successful locate dispatches `map:locate`
 * (detail: { longitude, latitude }) on the map root.
 *
 *   <MapControls showCompass showLocate showFullscreen />
 */
import { cn } from '../../lib/utils';

interface Props {
  /** Corner of the map (default: "bottom-right"). */
  position?: 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';
  showZoom?: boolean;
  showCompass?: boolean;
  showLocate?: boolean;
  showFullscreen?: boolean;
  class?: string;
}

const {
  position = 'bottom-right',
  showZoom = true,
  showCompass = false,
  showLocate = false,
  showFullscreen = false,
  class: className,
} = Astro.props;

const POSITIONS: Record<NonNullable<Props['position']>, string> = {
  'top-left': 'top-2 left-2',
  'top-right': 'top-2 right-2',
  'bottom-left': 'bottom-2 left-2',
  // bottom-right sits above MapLibre's compact attribution control
  'bottom-right': 'bottom-10 right-2',
};

const GROUP =
  'flex flex-col overflow-hidden rounded-md border border-border bg-background shadow-sm ' +
  '[&>button:not(:last-child)]:border-b [&>button:not(:last-child)]:border-border';

const BTN =
  'flex size-8 cursor-pointer items-center justify-center transition-colors ' +
  'first:rounded-t-md last:rounded-b-md hover:bg-muted ' +
  'focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-ring focus-visible:outline-none ' +
  'disabled:pointer-events-none disabled:opacity-50';
---

<div
  data-astro-shad-map-controls
  class={cn('absolute z-10 flex flex-col gap-1.5', POSITIONS[position], className)}
>
  {
    showZoom && (
      <div class={GROUP}>
        <button type="button" class={BTN} data-map-action="zoom-in" aria-label="Zoom in">
          <svg
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            stroke-linecap="round"
            stroke-linejoin="round"
            class="size-4"
          >
            <path d="M5 12h14" />
            <path d="M12 5v14" />
          </svg>
        </button>
        <button type="button" class={BTN} data-map-action="zoom-out" aria-label="Zoom out">
          <svg
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            stroke-linecap="round"
            stroke-linejoin="round"
            class="size-4"
          >
            <path d="M5 12h14" />
          </svg>
        </button>
      </div>
    )
  }

  {
    showCompass && (
      <div class={GROUP}>
        <button
          type="button"
          class={BTN}
          data-map-action="compass"
          aria-label="Reset bearing to north"
        >
          <svg
            data-compass-needle
            viewBox="0 0 24 24"
            class="size-5"
            style="transform-style: preserve-3d"
          >
            <path d="M12 2L16 12H12V2Z" class="fill-red-500" />
            <path d="M12 2L8 12H12V2Z" class="fill-red-300" />
            <path d="M12 22L16 12H12V22Z" class="fill-muted-foreground/60" />
            <path d="M12 22L8 12H12V22Z" class="fill-muted-foreground/30" />
          </svg>
        </button>
      </div>
    )
  }

  {
    showLocate && (
      <div class={GROUP}>
        <button
          type="button"
          class={BTN}
          data-map-action="locate"
          aria-label="Find my location"
        >
          <svg
            data-locate-icon
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            stroke-linecap="round"
            stroke-linejoin="round"
            class="size-4"
          >
            <line x1="2" x2="5" y1="12" y2="12" />
            <line x1="19" x2="22" y1="12" y2="12" />
            <line x1="12" x2="12" y1="2" y2="5" />
            <line x1="12" x2="12" y1="19" y2="22" />
            <circle cx="12" cy="12" r="7" />
          </svg>
          <svg
            data-locate-spinner
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            stroke-linecap="round"
            stroke-linejoin="round"
            class="hidden size-4 animate-spin"
          >
            <path d="M21 12a9 9 0 1 1-6.219-8.56" />
          </svg>
        </button>
      </div>
    )
  }

  {
    showFullscreen && (
      <div class={GROUP}>
        <button
          type="button"
          class={BTN}
          data-map-action="fullscreen"
          aria-label="Toggle fullscreen"
        >
          <svg
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            stroke-width="2"
            stroke-linecap="round"
            stroke-linejoin="round"
            class="size-4"
          >
            <path d="M8 3H5a2 2 0 0 0-2 2v3" />
            <path d="M21 8V5a2 2 0 0 0-2-2h-3" />
            <path d="M3 16v3a2 2 0 0 0 2 2h3" />
            <path d="M16 21h3a2 2 0 0 0 2-2v-3" />
          </svg>
